#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,a[1000001],maxn=1,sum=1;
    cin>>n;
    for(int i=1;i<=n;i++)cin>>a[i];
    for(int i=2;i<=n;i++){
        if(a[i]>a[i-1])sum++;
        else{
            maxn=max(maxn,sum);
            sum=1;
        }
    }
    maxn=max(maxn,sum);
    cout<<maxn;
    return 0;
}
